  {
    const APInt *C0, *C2, *MaskC;
    Value *Sub;
    BinaryOperator *SubI;
    if (match(Op0, m_APInt(C0)) &&
        match(Op1, m_OneUse(m_And(m_OneUse(m_Value(Sub)), m_APInt(MaskC)))) &&
        match(Sub, m_Sub(m_APInt(C2), m_Value(X))) &&
        (SubI = dyn_cast<BinaryOperator>(Sub)) && SubI->hasNoUnsignedWrap()) {
      if (*C0 == (*C2 & *MaskC)) {
        // Check that MaskC is a contiguous mask (i.e., of the form ~((1 << m) - 1) & ((1 << n) - 1))
        // This is equivalent to checking that MaskC + 1 is a power of 2, or
        // MaskC is of the form 0b111...000... (some number of 1s followed by some number of 0s)
        // Actually, we need to check that MaskC has the form: high bits are 1, low bits are 0
        // This is equivalent to: MaskC & (MaskC + 1) == 0 (for the low bits) and MaskC is not 0
        // But more precisely, we need (C0 - 1) & MaskC to be MaskC with some lower bits cleared
        // Actually, let's just check that MaskC is of the form: all 1s from bit k to bit n-1, and 0s elsewhere
        // This is equivalent to: MaskC & (MaskC + 1) == 0 && MaskC != 0
        // But this only checks that the low bits are 0 and there's a transition from 0 to 1
        // We also need to check that all bits above the transition are 1
        // This is equivalent to: (MaskC | (MaskC + 1)) == all ones
        APInt MaskPlusOne = *MaskC + 1;
        if (MaskPlusOne.isPowerOf2() || (*MaskC | MaskPlusOne).isAllOnes()) {
          APInt NewMask = *C0 | ((*C0 - 1) & *MaskC);
          return BinaryOperator::CreateAnd(X, ConstantInt::get(Ty, NewMask));
        }
      }
    }
  }
